module RefModule(CLK, EN, TE, DATA, Q);input CLK, EN, TE;
  input [31:0] DATA;
  output reg [31:0] Q;

  wire gated_clk;

  wire __gated_clk_tmp = (EN && !TE) ? CLK : 1'b0;
  assign gated_clk = __gated_clk_tmp;

  always @(posedge gated_clk) begin
    if (EN && !TE) begin
      Q <= DATA;
    end
  end

endmodule
